<script>
$(document).ready(function() {
    $('#reload-button').click(function() {
        // Add a random query string to prevent caching
        let timestamp = new Date().getTime();
        $('#captcha-image').attr('src', '{{ route("captcha.image") }}?t=' + timestamp);
    });
});



document.addEventListener('DOMContentLoaded', function () {
    const form = document.getElementById('enquireForm');
    const submitButton = form.querySelector('button[type="submit"]');
    const fullName = document.getElementById('full_name');
    const companyName = document.getElementById('company_name');
    const phone = document.getElementById('phone');
    const email = document.getElementById('email');
    const customDetails = document.getElementById('custom_details');
    const custom_captcha = document.getElementById('custom_captcha');

    const fullNameError = document.getElementById('full_name_error');
    const companyNameError = document.getElementById('company_name_error');
    const phoneError = document.getElementById('phone_error');
    const emailError = document.getElementById('email_error');
    const customDetailsError = document.getElementById('custom_details_error');
    const custom_captcha_error = document.getElementById('custom_captcha_error');

    function isValidEmail(email) {
        const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return re.test(email);
    }

    email.addEventListener('keyup', function() {
        if (isValidEmail(email.value.trim())) {
            emailError.style.display = 'none';
        }
    });

    form.addEventListener('submit', function(e) {
        e.preventDefault(); // prevent default submission
        let isValid = true;

        // Validate fields
        if (fullName.value.trim() === '') { fullNameError.style.display = 'block'; isValid = false; } else { fullNameError.style.display = 'none'; }
        if (companyName.value.trim() === '') { companyNameError.style.display = 'block'; isValid = false; } else { companyNameError.style.display = 'none'; }
        if (phone.value.trim() === '' || phone.value.trim().length < 7) { phoneError.style.display = 'block'; isValid = false; } else { phoneError.style.display = 'none'; }
        if (!isValidEmail(email.value.trim())) { emailError.style.display = 'block'; isValid = false; } else { emailError.style.display = 'none'; }
        if (customDetails.value.trim() === '') { customDetailsError.style.display = 'block'; isValid = false; } else { customDetailsError.style.display = 'none'; }
        if (custom_captcha.value.trim() === '') { custom_captcha_error.style.display = 'block'; isValid = false; } else { custom_captcha_error.style.display = 'none'; }

        if (!isValid) return; // stop if any field is invalid

        // Disable submit button while checking captcha
        submitButton.textContent = 'Verifying captcha...';
        submitButton.disabled = true;

        // AJAX captcha verification
        $.ajax({
            url: '{{ route("captcha.verify") }}',
            type: 'POST',
            data: {
                _token: '{{ csrf_token() }}',
                custom_captcha: custom_captcha.value.trim()
            },
            success: function(response) {
                if (response.success) {
                    // Captcha correct → submit form
                    submitButton.textContent = 'Submitting...';
                    form.submit();
                } else {
                    // Captcha incorrect → show error and re-enable button
                    custom_captcha_error.style.display = 'block';
                    custom_captcha_error.textContent = response.message;
                    submitButton.textContent = 'Submit';
                    submitButton.disabled = false;
                }
            },
            error: function() {
                alert('Something went wrong. Please try again.');
                submitButton.textContent = 'Submit';
                submitButton.disabled = false;
            }
        });
    });
});
</script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/gsap.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.2/ScrollTrigger.min.js"></script>
<script>
    gsap.registerPlugin(ScrollTrigger);

    function splitTextKeepHTML(element) {
        element.childNodes.forEach(node => {
            if (node.nodeType === Node.TEXT_NODE && node.textContent.trim() !== '') {
                let words = node.textContent.split(/(\s+)/); // split including spaces
                words.forEach(word => {
                    let span = document.createElement("span");
                    span.style.display = "inline-block";
                    span.style.whiteSpace = "pre"; // preserve spacing
                    span.textContent = word;
                    element.insertBefore(span, node);
                });
                element.removeChild(node);
            } else if (node.nodeType === Node.ELEMENT_NODE) {
                splitTextKeepHTML(node); // recursive for inner tags
            }
        });
    }

    document.querySelectorAll(".gsap_text").forEach(el => {
        splitTextKeepHTML(el);

        const spans = el.querySelectorAll("span");

        gsap.set(spans, { opacity: 0.1 });

        gsap.to(spans, {
            opacity: 1,
            stagger: 0.02,         // Faster stagger
            duration: 0.4,         // Short duration per word
            ease: "power1.out",
            scrollTrigger: {
                trigger: el,
                start: "top 85%",
                end: "bottom 15%",
                scrub: true
            }
        });
    });
</script>


